  ],
  "rows": [
    {
      "Item": "1",
      "Control": "Reset button",
      "Description": "The Reset button returns the printer to default settings and is always present if users are not logged in. The Reset button is not present when the Sign Out button is present. Touch the Reset button to resume and release jobs from the previous pause state and interrupt mode, reset the quick copy count in the copy count field, exit special modes, reset the display language and the keyboard layout."
    },
    {
      "Item": "2",
      "Control": "Sign In or Sign Out button",
      "Description": "Touch the Sign In button to access secured features. Touch the Sign Out button to sign out of the printer. The printer restores all options to the default settings. NOTE: This button displays only if the administrator has configured the printer to require permission for access to features."
    }
  ],
  "source": "docling"
}

