  ],
  "rows": [
    {
      "Button": "Thumbnail and page view buttons",
      "Button function": "Use these buttons to toggle between single-page view and \nthumbnail view. More options are available in thumbnail \nview than in single-page view."
    },
    {
      "Button": "Zoom buttons",
      "Button function": "Use these buttons to zoom in or out on the selected page.\nNOTE:\nSelect only one page at a time to use these \nbuttons."
    },
    {
      "Button": "Rotate button",
      "Button function": "Use this button to rotate the page 180 degrees.\nNOTE:\nThis button is available only in the thumbnail view."
    },
    {
      "Button": "Delete button",
      "Button function": "Use this button to delete the selected pages.\nNOTE:\nThis button is available only in the thumbnail view."
    },
    {
      "Button": "Arrow buttons",
      "Button function": "Use these buttons to rearrange the pages within the \ndocument. Select one or more pages and move them to \nthe left or right.\nNOTE:\nThese buttons are available only in the thumbnail \nview."
    },
    {
      "Button": "Add page button",
      "Button function": "Use this button to add a page to the document. The printer \nprompts to scan additional pages."
    }
  ]
}

