    {
      "Menuitem": "Fax Send Speed",
      "Description": "The Fax Send Speed setting sets the modembit rate (measured in bits per second) of the Analog Fax modemwhile sending a fax. ● Fast (v.34 - 33.6k) ● Medium (v.17 - 14.4k) ● Slow (v.29 - 9.6k)"
    },
    {
      "Menuitem": "Line Monitor Volume",
      "Description": "Use the Line Monitor Volume setting to control the printer's dialing volume level when sending faxes."
    },
    {
      "Menuitem": "DialingMode",
      "Description": "The Dialing Modesetting sets the type of dialing that is used: either tone (touch- tone phones) or pulse (rotary-dial phones)."
    },
    {
      "Menuitem": "Dialing Prefix",
      "Description": "The Dialing Prefix setting allows you to enter a prefix number (such as a \"9\" to access an outside line) when dialing. This prefix number is automatically added to all phone numbers when dialed."
    },
    {
      "Menuitem": "Detect Dial Tone",
      "Description": "The Detect Dial Tone setting determines whether the fax checks for a dial tone before sending a fax."
    }
